insert into public.security_aliases (
  id,
  security_id,
  alias_text_normalized,
  alias_source,
  confidence
)
select
  alias_data.id::uuid,
  security.id,
  alias_data.alias_text_normalized,
  alias_data.alias_source,
  alias_data.confidence::numeric
from (select id from public.securities where provider_name = 'manual_fund_nav' and provider_symbol = 'IE0008248803' limit 1) as security(id)
cross join (
values
  ('ccef277c-08cc-5cf0-aba1-92a1812a1224', 'VANGUARD EUROZONE STOCK INDEX FUND EUR ACC', 'manual', 1.0)
) as alias_data(id, alias_text_normalized, alias_source, confidence)
on conflict (security_id, alias_text_normalized) do nothing;

